// frontend/src/components/Radar.jsx
import React, { useEffect, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

/* ========= Map-level guard (prevents getCenter on a dead map) ========= */
if (typeof L !== "undefined" && L.Map && !L.Map.__wxPatched) {
  const M = L.Map.prototype;
  const _resetView = M._resetView;
  M._resetView = function (...args) {
    // If map is not initialized or container is gone, abort
    if (!this || !this._container || !this._loaded) return;
    return _resetView.call(this, ...args);
  };
  L.Map.__wxPatched = true;
}

/* ========= GridLayer guard (prevents _fadeAnimated crashes) ========= */
if (typeof L !== "undefined" && L.GridLayer && !L.GridLayer.__wxPatched) {
  const G = L.GridLayer.prototype;
  const _tileReady = G._tileReady;
  const _tileOnLoad = G._tileOnLoad;
  const _tileOnError = G._tileOnError;

  G._tileReady = function (tile, err, key) {
    if (!this || !this._map) return;
    return _tileReady.call(this, tile, err, key);
  };
  if (_tileOnLoad) {
    G._tileOnLoad = function (e) {
      if (!this || !this._map) return;
      return _tileOnLoad.call(this, e);
    };
  }
  if (_tileOnError) {
    G._tileOnError = function (e) {
      if (!this || !this._map) return;
      return _tileOnError.call(this, e);
    };
  }
  L.GridLayer.__wxPatched = true;
}

/* ========= Utility ========= */
function safeRemoveTileLayer(map, layer) {
  if (!layer) return;
  try { layer.off(); } catch {}
  try { typeof layer._abortLoading === "function" && layer._abortLoading(); } catch {}
  try { layer._container && (layer._container.innerHTML = ""); } catch {}
  try { map && map.hasLayer(layer) && map.removeLayer(layer); } catch {}
}

const OWM_KEY = process.env.REACT_APP_OWM_KEY || "";
const CENTER = [33.749, -84.388]; // ATL
const START_ZOOM = 6;

export default function Radar() {
  const mapRef = useRef(null);
  const aliveRef = useRef(false); // component mounted flag
  const baseRef = useRef(null);
  const overlayRef = useRef(null);
  const pendingRef = useRef(null);

  const [provider, setProvider] = useState("auto"); // auto | mesonet | rainviewer | owm
  const [base, setBase] = useState("osm"); // osm | dark

  const baseOptions = {
    osm: {
      url: "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",
      opts: { maxZoom: 19, zIndex: 100, crossOrigin: true },
      label: "OSM",
    },
    dark: {
      url: "https://tiles.stadiamaps.com/tiles/alidade_dark/{z}/{x}/{y}{r}.png",
      opts: { maxZoom: 19, zIndex: 100, crossOrigin: true },
      label: "Dark",
    },
  };

  const overlayMeta = {
    mesonet: {
      label: "Mesonet",
      url: "https://mesonet.agron.iastate.edu/cache/tile.py/1.0.0/nexrad-n0q-900913/{z}/{x}/{y}.png",
      opts: { opacity: 0.85, zIndex: 500, crossOrigin: true, noWrap: true },
      minZoom: 3, maxZoom: 12,
    },
    rainviewer: {
      label: "RainViewer",
      dynamic: true,
      opts: { opacity: 0.85, zIndex: 500, crossOrigin: true },
      minZoom: 0, maxZoom: 18,
    },
    owm: {
      label: "OWM",
      url: OWM_KEY
        ? `https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${OWM_KEY}`
        : "",
      opts: { opacity: 0.85, zIndex: 500, crossOrigin: true },
      minZoom: 0, maxZoom: 18,
    },
  };

  /* ---------- init map once ---------- */
  useEffect(() => {
    if (mapRef.current) return;
    aliveRef.current = true;

    const map = L.map("radar-map", {
      center: CENTER,
      zoom: START_ZOOM,
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
      fadeAnimation: false,
      zoomAnimation: false,
      inertia: false,
      // leave user interactions on; we’ll disable on unmount to avoid races
    });
    mapRef.current = map;

    // base
    const b = baseOptions[base] || baseOptions.osm;
    baseRef.current = L.tileLayer(b.url, b.opts).addTo(map);

    // keep overlay zoom in range + refresh tiles after zoom
    const onZoomEnd = () => {
      if (!aliveRef.current) return;
      const id = overlayRef.current?.__providerId;
      if (!id) return;
      const meta = overlayMeta[id];
      if (!meta) return;
      const z = map.getZoom();
      if (meta.maxZoom != null && z > meta.maxZoom) {
        try { map.setZoom(meta.maxZoom, { animate: false }); } catch {}
      } else if (meta.minZoom != null && z < meta.minZoom) {
        try { map.setZoom(meta.minZoom, { animate: false }); } catch {}
      }
      try { overlayRef.current?.redraw?.(); } catch {}
    };
    map.on("zoomend", onZoomEnd);

    setTimeout(() => map.invalidateSize(), 0);

    return () => {
      // prevent any late handlers from running against a dead map
      aliveRef.current = false;

      try {
        map.off();
        map.dragging?.disable();
        map.touchZoom?.disable();
        map.doubleClickZoom?.disable();
        map.scrollWheelZoom?.disable();
        map.boxZoom?.disable();
        map.keyboard?.disable();
      } catch {}

      safeRemoveTileLayer(map, pendingRef.current);
      safeRemoveTileLayer(map, overlayRef.current);
      safeRemoveTileLayer(map, baseRef.current);

      try { map.remove(); } catch {}
      mapRef.current = null;
    };
  }, []); // run once

  /* ---------- swap base safely ---------- */
  useEffect(() => {
    const map = mapRef.current; if (!map) return;
    const b = baseOptions[base] || baseOptions.osm;
    if (baseRef.current) safeRemoveTileLayer(map, baseRef.current);
    baseRef.current = L.tileLayer(b.url, b.opts).addTo(map);
  }, [base]);

  const clampZoomFor = (id) => {
    const map = mapRef.current; if (!map || !aliveRef.current) return;
    const meta = overlayMeta[id]; if (!meta) return;
    let z = map.getZoom();
    if (meta.maxZoom != null && z > meta.maxZoom) z = meta.maxZoom;
    if (meta.minZoom != null && z < meta.minZoom) z = meta.minZoom;
    if (z !== map.getZoom()) {
      try { map.setZoom(z, { animate: false }); } catch {}
    }
  };

  const createRainviewerLayer = async () => {
    const meta = await fetch("https://api.rainviewer.com/public/weather-maps.json").then(r => r.json());
    const host = meta?.host || "";
    const frames = [...(meta?.radar?.past || []), ...(meta?.radar?.nowcast || [])];
    const last = frames.at(-1)?.time;
    if (!host || !last) throw new Error("No RainViewer frames");
    return L.tileLayer(`${host}/v2/radar/${last}/256/{z}/{x}/{y}.png`, overlayMeta.rainviewer.opts);
  };

  const mountOverlay = (layer, id) => {
    const map = mapRef.current; if (!map || !aliveRef.current) return;
    pendingRef.current = layer;
    layer.__providerId = id;

    layer
      .on("load", () => {
        if (!aliveRef.current || !mapRef.current) return;
        safeRemoveTileLayer(map, overlayRef.current);
        overlayRef.current = pendingRef.current;
        pendingRef.current = null;
        clampZoomFor(id);
      })
      .on("tileerror", () => {
        if (!aliveRef.current || !mapRef.current) return;
        safeRemoveTileLayer(map, pendingRef.current);
        pendingRef.current = null;
      })
      .addTo(map);
  };

  /* ---------- change overlay when provider changes ---------- */
  useEffect(() => {
    const map = mapRef.current; if (!map || !aliveRef.current) return;

    const setAuto = async () => {
      // try Mesonet -> RainViewer -> OWM
      try {
        const l1 = L.tileLayer(overlayMeta.mesonet.url, overlayMeta.mesonet.opts);
        mountOverlay(l1, "mesonet");
      } catch {}
      // We still attempt RV/OWM if Mesonet doesn't fully load quickly
      try {
        const l2 = await createRainviewerLayer();
        mountOverlay(l2, "rainviewer");
      } catch {}
      if (overlayMeta.owm.url) {
        const l3 = L.tileLayer(overlayMeta.owm.url, overlayMeta.owm.opts);
        mountOverlay(l3, "owm");
      }
    };

    const setManual = async (id) => {
      if (id === "mesonet") {
        mountOverlay(L.tileLayer(overlayMeta.mesonet.url, overlayMeta.mesonet.opts), "mesonet");
      } else if (id === "rainviewer") {
        try { mountOverlay(await createRainviewerLayer(), "rainviewer"); } catch {}
      } else if (id === "owm") {
        if (!overlayMeta.owm.url) return;
        mountOverlay(L.tileLayer(overlayMeta.owm.url, overlayMeta.owm.opts), "owm");
      }
    };

    if (provider === "auto") setAuto();
    else setManual(provider);
  }, [provider]);

  return (
    <div className="relative rounded-2xl overflow-hidden backdrop-blur-xl bg-black/40 ring-1 ring-white/10">
      {/* Compact controls */}
      <div className="flex items-center justify-between px-3 py-2 gap-2">
        <div className="text-sm opacity-80">Radar</div>
        <div className="flex gap-2">
          <select
            className="text-xs px-2 py-1 rounded"
            style={{ backgroundColor: "#fff", color: "#000" }}
            value={provider}
            onChange={(e) => setProvider(e.target.value)}
            aria-label="Provider"
          >
            <option value="auto">Auto (fastest)</option>
            <option value="mesonet">Mesonet</option>
            <option value="rainviewer">RainViewer</option>
            <option value="owm" disabled={!OWM_KEY}>
              OpenWeather {OWM_KEY ? "" : "(set key)"}
            </option>
          </select>
          <select
            className="text-xs px-2 py-1 rounded"
            style={{ backgroundColor: "#fff", color: "#000" }}
            value={base}
            onChange={(e) => setBase(e.target.value)}
            aria-label="Base map"
          >
            <option value="osm">OSM</option>
            <option value="dark">Dark</option>
          </select>
        </div>
      </div>

      <div id="radar-map" style={{ height: 320, width: "100%" }} />
    </div>
  );
}
